src/core/extract.hpp — RegionMetrics and extract_metrics()<pre><code>#pragma once

#include &lt;array&gt;
#include &lt;cstddef&gt;
#include &lt;filesystem&gt;
#include &lt;limits&gt;
#include &lt;string_view&gt;
#include &lt;unordered_map&gt;

namespace cfextract {

struct CpGSiteCount {
  size_t methylated   = 0;
  size_t unmethylated = 0;
};

struct MethylationStats {
  double mean       = std::numeric_limits&lt;double&gt;::quiet_NaN();
  double entropy    = std::numeric_limits&lt;double&gt;::quiet_NaN();
  double frac_high  = std::numeric_limits&lt;double&gt;::quiet_NaN();
  double frac_low   = std::numeric_limits&lt;double&gt;::quiet_NaN();
  double median     = std::numeric_limits&lt;double&gt;::quiet_NaN();
};

struct FragLenStats {
  double mean                = std::numeric_limits&lt;double&gt;::quiet_NaN();
  double std_dev             = std::numeric_limits&lt;double&gt;::quiet_NaN();
  double frac_subnucleosomal = std::numeric_limits&lt;double&gt;::quiet_NaN();
  double frac_nucleosomal    = std::numeric_limits&lt;double&gt;::quiet_NaN();
  double ratio_mono_di       = std::numeric_limits&lt;double&gt;::quiet_NaN();
};

struct RegionMetrics {
  // end motifs: 4-mer string → read count
  std::unordered_map&lt;std::string, size_t&gt; end_motifs;
  // fragment lengths: index = length in bp, value = count; &gt;1000 bp clamped to index 1000
  std::array&lt;size_t, 1001&gt; frag_len_hist{};
  // summary statistics derived from frag_len_hist (NaN if no fragments observed)
  FragLenStats fl_stats;
  // CpG methylation summary statistics (NaN if no covered sites)
  MethylationStats methylation;
  // read start/end position histograms: (pos / 100_000) → count, for summary plots only
  std::unordered_map&lt;int64_t, size_t&gt; start_pos_hist;
  std::unordered_map&lt;int64_t, size_t&gt; end_pos_hist;
};


RegionMetrics
extract_metrics
(
  std::filesystem::path aln_fp,
  std::string_view contig,
  int64_t start = 0,
  int64_t stop  = -1
);

}
</code></pre>

src/core/access.hpp<pre><code>#pragma once

#include &lt;filesystem&gt;

#include &lt;htslib/hts.h&gt;
#include &lt;htslib/sam.h&gt;

namespace htsacc {

struct GenomicRegion {
  int32_t tid;
  int64_t start;
  int64_t stop;
};

struct AlnFile {
  htsFile* f=nullptr;
  sam_hdr_t* hdr=nullptr;
  hts_idx_t* idx=nullptr;

  AlnFile() = default;
  AlnFile(const AlnFile&amp;) = delete;
  AlnFile&amp; operator=(const AlnFile&amp;) = delete;

  AlnFile (AlnFile&amp;&amp; o) noexcept {
    f = o.f;
    hdr = o.hdr;
    idx = o.idx;
    o.f = nullptr;
    o.hdr = nullptr;
    o.idx = nullptr;
  }

  ~AlnFile () {
    if (idx) {
      hts_idx_destroy (idx);
    }
    if (hdr) {
      sam_hdr_destroy (hdr);
    }
    if (f) {
      hts_close (f);
    }
  }
};

AlnFile
open_aln
(std::filesystem::path fp);

hts_itr_t*
get_region
(const AlnFile&amp; aln, GenomicRegion reg);

};
</code></pre> <p><code>AlnFile</code> is a non-copyable RAII wrapper around the three htslib handles required for indexed BAM access (<code>htsFile*</code>, <code>sam_hdr_t*</code>, <code>hts_idx_t*</code>). The destructor frees all three in reverse-acquisition order.</p> <p><code>open_aln()</code> opens the file and loads the BAI/CSI index, throwing on any failure. <code>get_region()</code> returns an <code>hts_itr_t*</code> iterator for the specified region; the caller is responsible for freeing it with <code>hts_itr_destroy()</code>.</p>

src/core/features.hpp<pre><code>#pragma once

#include &lt;string&gt;

#include &lt;htslib/sam.h&gt;

// individual feature extractors
namespace feature_extractors {

std::string
get_end_motif
(const bam1_t* b, size_t motif_sz);

}
</code></pre> <p><code>get_end_motif()</code> extracts the 4-mer at the 5′ end of the fragment:</p> <ul> <li>Forward-strand reads (<code>BAM_FREVERSE</code> not set): first 4 bases of the read sequence.</li> <li>Reverse-strand reads (<code>BAM_FREVERSE</code> set): last 4 bases, reversed and complemented — this gives the 5′ end of the complementary strand, i.e. the actual fragment end.</li> </ul> <p>Bismark bisulfite alignment converts unmethylated C to T, so motif distributions are T/A-biased compared to non-bisulfite cfDNA.</p>

src/core/stats.hpp<pre><code>#pragma once

#include &lt;array&gt;
#include &lt;cstddef&gt;
#include &lt;unordered_map&gt;

#include "extract.hpp"

namespace cfextract {

MethylationStats
compute_meth_stats (const std::unordered_map&lt;int64_t, CpGSiteCount&gt;&amp; sites);

FragLenStats
compute_fl_stats (const std::array&lt;size_t, 1001&gt;&amp; hist);

}
</code></pre> <p>Both functions return all-NaN structs if their inputs are empty (no fragments or no covered CpG sites). The NaN sentinel propagates to Python via the pybind11 bindings and is detected in <code>metrics_to_features()</code> — absent data becomes an absent key rather than a NaN value in the <code>Features</code> dict.</p>
